+        if nsample == 0 || ngood == 0 {
+            return 0;
+        }
+        if nsample >= total {
+            return ngood;
+        }
+        let mut good_remaining = ngood;
+        let mut total_remaining = total;
+        let mut successes = 0u64;
+        for _ in 0..nsample {
+            let u = self.next_f64();
+            if u < good_remaining as f64 / total_remaining as f64 {
+                successes += 1;
+                good_remaining -= 1;
+            }
+            total_remaining -= 1;
+            if good_remaining == 0 || total_remaining == 0 {
+                break;
+            }
+        }
